// ─── Color helpers ──────────────────────────────────────────────────────────

function winRateColor(v) {
  const n = Number(v);
  if (!isFinite(n)) return '#90A3AF';
  if (n >= 55) return '#22C55E';
  if (n >= 45) return '#F59E0B';
  return '#EF4444';
}

function pfColor(v) {
  const n = Number(v);
  if (!isFinite(n)) return '#90A3AF';
  if (n >= 2.0) return '#22C55E';
  if (n >= 1.5) return '#F59E0B';
  if (n < 1.0) return '#EF4444';
  return '#E5E7DB';
}

function sharpeColor(v) {
  const n = Number(v);
  if (!isFinite(n)) return '#90A3AF';
  if (n >= 1.5) return '#22C55E';
  if (n >= 1.0) return '#F59E0B';
  return '#EF4444';
}

function statusPill(status) {
  const st = (status || '').toLowerCase();
  if (st === 'live') return { bg: `${'#22C55E'}20`, color: '#22C55E', label: 'LIVE' };
  if (st === 'promoted') return { bg: `${'#22C55E'}20`, color: '#22C55E', label: 'PROMOTED' };
  if (st === 'pending') return { bg: `${'#F59E0B'}20`, color: '#F59E0B', label: 'PENDING' };
  if (st === 'suppressed') return { bg: `${'#EF4444'}20`, color: '#EF4444', label: 'SUPPRESSED' };
  if (st === 'backtest') return { bg: `${'#60A5FA'}20`, color: '#60A5FA', label: 'BACKTEST' };
  return { bg: `${'#90A3AF'}15`, color: '#90A3AF', label: (status || 'UNKNOWN').toUpperCase() };
}

function directionPill(dir) {
  const d = (dir || '').toLowerCase();
  if (d === 'long') return { bg: `${'#22C55E'}20`, color: '#22C55E', label: 'LONG' };
  if (d === 'short') return { bg: `${'#EF4444'}20`, color: '#EF4444', label: 'SHORT' };
  return { bg: `${'#60A5FA'}20`, color: '#60A5FA', label: (dir || '--').toUpperCase() };
}

